const searchMemos = `-- name: SearchMemos :many
SELECT m.id, m.session_id, m.content, m.content_html, m.metadata, m.pinned,
       m.created_at, m.updated_at, m.deleted_at
FROM memos m
WHERE m.content ILIKE '%' || $1 || '%'
  AND m.deleted_at IS NULL
  AND (m.created_at < $2 OR (m.created_at = $2 AND m.id < $3))
ORDER BY m.created_at DESC, m.id DESC
LIMIT $4
`

type SearchMemosParams struct {
	Query           pgtype.Text        `json:"query"`
	CursorCreatedAt pgtype.Timestamptz `json:"cursor_created_at"`
	CursorID        int64              `json:"cursor_id"`
	PageLimit       int32              `json:"page_limit"`
}

func (q *Queries) SearchMemos(ctx context.Context, arg SearchMemosParams) ([]Memo, error) {
	rows, err := q.db.Query(ctx, searchMemos,
		arg.Query,
		arg.CursorCreatedAt,
		arg.CursorID,
		arg.PageLimit,
	)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	items := []Memo{}
	for rows.Next() {
		var i Memo
		if err := rows.Scan(
			&i.ID,
			&i.SessionID,
			&i.Content,
			&i.ContentHtml,
			&i.Metadata,
			&i.Pinned,
			&i.CreatedAt,
			&i.UpdatedAt,
			&i.DeletedAt,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

