const upsertDailyReport = `-- name: UpsertDailyReport :one
INSERT INTO daily_reports (report_date, session_count, total_memos, total_chars, chars_per_minute, active_minutes, hourly_distribution)
VALUES ($1, $2, $3, $4, $5, $6, $7)
ON CONFLICT (report_date) DO UPDATE SET
    session_count = EXCLUDED.session_count,
    total_memos = EXCLUDED.total_memos,
    total_chars = EXCLUDED.total_chars,
    chars_per_minute = EXCLUDED.chars_per_minute,
    active_minutes = EXCLUDED.active_minutes,
    hourly_distribution = EXCLUDED.hourly_distribution
RETURNING id, report_date, session_count, total_memos, total_chars,
          chars_per_minute, active_minutes, hourly_distribution, created_at
`

type UpsertDailyReportParams struct {
	ReportDate         pgtype.Date     `json:"report_date"`
	SessionCount       int32           `json:"session_count"`
	TotalMemos         int32           `json:"total_memos"`
	TotalChars         int32           `json:"total_chars"`
	CharsPerMinute     pgtype.Float8   `json:"chars_per_minute"`
	ActiveMinutes      int32           `json:"active_minutes"`
	HourlyDistribution json.RawMessage `json:"hourly_distribution"`
}

func (q *Queries) UpsertDailyReport(ctx context.Context, arg UpsertDailyReportParams) (DailyReport, error) {
	row := q.db.QueryRow(ctx, upsertDailyReport,
		arg.ReportDate,
		arg.SessionCount,
		arg.TotalMemos,
		arg.TotalChars,
		arg.CharsPerMinute,
		arg.ActiveMinutes,
		arg.HourlyDistribution,
	)
	var i DailyReport
	err := row.Scan(
		&i.ID,
		&i.ReportDate,
		&i.SessionCount,
		&i.TotalMemos,
		&i.TotalChars,
		&i.CharsPerMinute,
		&i.ActiveMinutes,
		&i.HourlyDistribution,
		&i.CreatedAt,
	)
	return i, err
}

const upsertTag = `-- name: UpsertTag :one
INSERT INTO tags (name) VALUES ($1)
ON CONFLICT (name) DO UPDATE SET name = EXCLUDED.name
RETURNING id, name, created_at
`

func (q *Queries) UpsertTag(ctx context.Context, name string) (Tag, error) {
	row := q.db.QueryRow(ctx, upsertTag, name)
	var i Tag
	err := row.Scan(&i.ID, &i.Name, &i.CreatedAt)
	return i, err
}
